    def parse_market(self, market: dict) -> Market:
        #
        #     {
        #       "name": "BTC-USD",
        #       "uiName": "BTC-USD",
        #       "category": "Crypto",
        #       "subCategory": "L1",
        #       "assetName": "BTC",
        #       "assetPrecision": 5,
        #       "collateralAssetName": "USD",
        #       "collateralAssetPrecision": 6,
        #       "description": "Bitcoin",
        #       "active": True,
        #       "status": "ACTIVE",
        #       "marketStats": {...},
        #       "tradingConfig": {
        #         "minOrderSize": "0.0001",
        #         "minOrderSizeChange": "0.00001",
        #         "minPriceChange": "1",
        #         "maxMarketOrderValue": "3000000",
        #         "maxLimitOrderValue": "15000000",
        #         "maxPositionValue": "60000000",
        #         "maxLeverage": "50.00",
        #         "hourlyFundingRateCap": "0.25",
        #         "maxNumOrders": "200",
        #         "limitPriceCap": "0.05",
        #         "limitPriceFloor": "0.05",
        #         "riskFactorConfig": [
        #           {
        #             "upperBound": "4000000",
        #             "riskFactor": "0.02",
        #             "isAvailableForUsers": True
        #           }
        #         ]
        #       },
        #       "l2Config": {...},
        #       "visibleOnUi": True,
        #       "createdAt": 1752829532673
        #     }
        #
        tradingConfig = self.safe_dict(market, 'tradingConfig', {})
        marketId = self.safe_string(market, 'name')
        baseId = self.safe_string(market, 'assetName')
        if baseId.find('SPOT') >= 0:
            baseId = baseId.replace('SPOT', '')
        quoteId = self.safe_string(market, 'collateralAssetName')
        base = self.safe_currency_code(baseId)
        quote = self.safe_currency_code(quoteId)
        if quoteId == 'USD':
            quote = 'USDC'
        status = self.safe_string(market, 'status')
        active = (status == 'ACTIVE')
        amountPrecision = self.safe_number(tradingConfig, 'minOrderSizeChange')
        pricePrecision = self.safe_number(tradingConfig, 'minPriceChange')
        maxLeverage = self.safe_number(tradingConfig, 'maxLeverage')
        minAmount = self.safe_number(tradingConfig, 'minOrderSize')
        maxCost = self.safe_number(tradingConfig, 'maxLimitOrderValue')
        created = self.safe_integer(market, 'createdAt')
        settleId = None
        settle = None
        symbol = base + '/' + quote
        isSpot = False
        type = self.safe_string_lower(market, 'type')
        contractSize = None
        linear = None
        inverse = None
        if type == 'spot':
            isSpot = True
        else:
            type = 'swap'
            settleId = quoteId
            settle = quote
            symbol += ':' + settle
            contractSize = self.parse_number('1')
            linear = True
            inverse = False
        return self.safe_market_structure({
            'id': marketId,
            'symbol': symbol,
            'base': base,
            'quote': quote,
            'settle': settle,
            'baseId': baseId,
            'quoteId': quoteId,
            'settleId': settleId,
            'type': type,
            'spot': isSpot,
            'margin': False,
            'swap': not isSpot,
            'future': False,
            'option': False,
            'active': active,
            'contract': not isSpot,
            'linear': linear,
            'inverse': inverse,
            'taker': self.safe_number(self.fees, 'taker'),
            'maker': self.safe_number(self.fees, 'maker'),
            'contractSize': contractSize,
            'expiry': None,
            'expiryDatetime': None,
            'strike': None,
            'optionType': None,
            'precision': {
                'amount': amountPrecision,
                'price': pricePrecision,
            },
            'limits': {
                'leverage': {
                    'min': self.parse_number('1'),
                    'max': maxLeverage,
                },
                'amount': {
                    'min': minAmount,
                    'max': None,
                },
                'price': {
                    'min': None,
                    'max': None,
                },
                'cost': {
                    'min': None,
                    'max': maxCost,
                },
            },
            'created': created,
            'info': market,
        })

