    def parse_currency(self, currency: dict) -> Currency:
        #
        #     {
        #       "id": 1,
        #       "name": "USD",
        #       "symbol": "USD",
        #       "description": "USD Collateral",
        #       "precision": 6,
        #       "isActive": True,
        #       "isCollateral": True,
        #       "starkexId": "0x1",
        #       "starkexResolution": 1000000,
        #       "l1Id": "0xa0b86991c6218b36c1d19d4a2e9eb0ce3606eb48",
        #       "l1Resolution": 1000000,
        #       "version": 3,
        #       "createdAt": 1752829532673,
        #       "type": "SPOT",
        #       "canBeUsedAsCollateral": True,
        #       "riskFactors": [],
        #       "availableForTradeFactors": []
        #     }
        #
        currencyId = self.safe_string(currency, 'symbol')
        if (currencyId is not None) and (currencyId.find('SPOT') >= 0):
            currencyId = currencyId.replace('SPOT', '')
        code = self.safe_currency_code(currencyId)
        if currencyId == 'USD':
            code = 'USDC'
        name = self.safe_string(currency, 'name')
        precision = self.safe_integer(currency, 'precision')
        isActive = self.safe_bool(currency, 'isActive')
        return self.safe_currency_structure({
            'id': currencyId,
            'code': code,
            'numericId': self.safe_integer(currency, 'id'),
            'name': name,
            'active': isActive,
            'deposit': True,
            'withdraw': True,
            'precision': math.pow(10, precision * -1),
            'type': 'other',
            'margin': self.safe_bool(currency, 'canBeUsedAsCollateral'),
            'info': currency,
        })

