    async def fetch_tickers(self, symbols: Strings = None, params={}) -> Tickers:
        """
        fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for all markets

        https://api.docs.extended.exchange/#get-markets

        :param str[] [symbols]: unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :returns dict: a dictionary of `ticker structures <https://docs.ccxt.com/?id=ticker-structure>`
        """
        await self.load_markets()
        symbols = self.market_symbols(symbols)
        request = {}
        if symbols is not None:
            marketIds = []
            for i in range(0, len(symbols)):
                market = self.market(symbols[i])
                marketIds.append(market['id'])
            request['market'] = marketIds
        response = await self.v1PublicGetInfoMarkets(self.extend(request, params))
        #
        #     {
        #       "status": "OK",
        #       "data": [
        #         {
        #           "name": "BTC-USD",
        #           "assetName": "BTC",
        #           "collateralAssetName": "USD",
        #           "marketStats": {
        #             "dailyVolume": "231016077.512960",
        #             ...
        #           },
        #           ...
        #         }
        #       ]
        #     }
        #
        data = self.safe_list(response, 'data', [])
        tickers = {}
        for i in range(0, len(data)):
            marketData = data[i]
            marketId = self.safe_string(marketData, 'name')
            market = self.safe_market(marketId)
            stats = self.safe_dict(marketData, 'marketStats', {})
            ticker = self.parse_ticker(stats, market)
            symbol = ticker['symbol']
            tickers[symbol] = ticker
        return self.filter_by_array_tickers(tickers, 'symbol', symbols)

    def parse_ticker(self, ticker, market: Market = None) -> Ticker:
        #
        #     {
        #       "dailyVolume": "231216165.666600",
        #       "dailyVolumeBase": "3027.36710",
        #       "dailyPriceChange": "181",
        #       "dailyPriceChangePercentage": "0.0024",
        #       "dailyLow": "75635",
        #       "dailyHigh": "77399",
        #       "lastPrice": "77026",
        #       "askPrice": "77026",
        #       "bidPrice": "77025",
        #       "markPrice": "77006.091897999984",
        #       "indexPrice": "77050.739529925005",
        #       "fundingRate": "0.000012",
        #       "nextFundingRate": 1777446000000,
        #       "openInterest": "114851569.088316",
        #       "openInterestBase": "1491.33012",
        #       "deleverageLevels": {
        #         "shortPositions": [
        #           {"level": 1, "rankingLowerBound": "-784.2884"},
        #           {"level": 2, "rankingLowerBound": "-2.1078"},
        #           {"level": 3, "rankingLowerBound": "-0.8754"},
        #           {"level": 4, "rankingLowerBound": "0.0000"}
        #         ],
        #         "longPositions": [
        #           {"level": 1, "rankingLowerBound": "-47747.2010"},
        #           {"level": 2, "rankingLowerBound": "-0.0131"},
        #           {"level": 3, "rankingLowerBound": "0.0019"},
        #           {"level": 4, "rankingLowerBound": "0.0032"}
        #         ]
        #       }
        #     }
        #
        symbol = self.safe_symbol(None, market)
        last = self.safe_number(ticker, 'lastPrice')
        percentageRaw = self.safe_string(ticker, 'dailyPriceChangePercentage')
        percentage = Precise.string_mul(percentageRaw, '100') if (percentageRaw is not None) else None
        return self.safe_ticker({
            'symbol': symbol,
            'timestamp': None,
            'datetime': None,
            'high': self.safe_number(ticker, 'dailyHigh'),
            'low': self.safe_number(ticker, 'dailyLow'),
            'bid': self.safe_number(ticker, 'bidPrice'),
            'bidVolume': None,
            'ask': self.safe_number(ticker, 'askPrice'),
            'askVolume': None,
            'vwap': None,
            'open': None,
            'close': last,
            'last': last,
            'previousClose': None,
            'change': self.safe_number(ticker, 'dailyPriceChange'),
            'percentage': percentage,
            'average': None,
            'baseVolume': self.safe_number(ticker, 'dailyVolumeBase'),
            'quoteVolume': self.safe_number(ticker, 'dailyVolume'),
            'markPrice': self.safe_number(ticker, 'markPrice'),
            'indexPrice': self.safe_number(ticker, 'indexPrice'),
            'info': ticker,
        }, market)

    async def fetch_order_book(self, symbol: str, limit: Int = None, params={}) -> OrderBook:
        """
        fetches information on open orders with bid(buy) and ask(sell) prices, volumes and other data

        https://api.docs.extended.exchange/#get-market-order-book

        :param str symbol: unified symbol of the market to fetch the order book for
        :param int [limit]: the maximum amount of order book entries to return
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :returns dict: A dictionary of `order book structures <https://docs.ccxt.com/?id=order-book-structure>`
        """
        await self.load_markets()
        market = self.market(symbol)
        request = {
            'market': market['id'],
        }
        response = await self.v1PublicGetInfoMarketsMarketOrderbook(self.extend(request, params))
        #
        #     {
        #       "status": "OK",
        #       "data": {
        #         "market": "BTC-USD",
        #         "bid": [
        #           {
        #             "qty": "14.46084",
        #             "price": "76214"
        #           }
        #         ],
        #         "ask": [
        #           {
        #             "qty": "0.11585",
        #             "price": "76215"
        #           }
        #         ]
        #       }
        #     }
        #
        data = self.safe_dict(response, 'data', {})
        timestamp = self.milliseconds()
        orderbook = self.parse_order_book(data, market['symbol'], timestamp, 'bid', 'ask', 'price', 'qty')
        if limit is not None:
            orderbook['bids'] = self.array_slice(orderbook['bids'], 0, limit)
            orderbook['asks'] = self.array_slice(orderbook['asks'], 0, limit)
        return orderbook

