    def parse_funding_history(self, history, market: Market = None):
        #
        #     {
        #         "id": 8341,
        #         "accountId": 3137,
        #         "market": "BNB-USD",
        #         "positionId": 1821237954501148672,
        #         "side": "LONG",
        #         "size": "1.116",
        #         "value": "560.77401888",
        #         "markPrice": "502.48568",
        #         "fundingFee": "0",
        #         "fundingRate": "0",
        #         "paidTime": 1723147241346
        #     }
        #
        marketId = self.safe_string(history, 'market')
        market = self.safe_market(marketId, market)
        timestamp = self.safe_integer(history, 'paidTime')
        return {
            'info': history,
            'symbol': market['symbol'],
            'code': market['settle'],
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
            'id': self.safe_string(history, 'id'),
            'amount': self.safe_number(history, 'fundingFee'),
            'rate': self.safe_number(history, 'fundingRate'),
        }

    def parse_funding_histories(self, histories, market: Market = None, since: Int = None, limit: Int = None) -> List[FundingHistory]:
        result = []
        for i in range(0, len(histories)):
            result.append(self.parse_funding_history(histories[i], market))
        symbol = None if (market is None) else market['symbol']
        return self.filter_by_symbol_since_limit(result, symbol, since, limit)

    def parse_trade(self, trade, market: Market = None) -> Trade:
        #
        # fetchTrades
        #
        #     {
        #       "i": 2.049676905958871e+18,
        #       "m": "BTC-USD",
        #       "S": "SELL",
        #       "tT": "TRADE",
        #       "T": 1777516030193,
        #       "p": "76140",
        #       "q": "0.00165"
        #     }
        #
        # fetchMyTrades
        #
        #     {
        #         "id": 1,
        #         "orderId": 1784980437895231232,
        #         "externalId": "ExtId-1",
        #         "accountId": 1,
        #         "market": "BTC-USD",
        #         "side": "BUY",
        #         "price": "39000",
        #         "qty": "0.2",
        #         "value": "7800",
        #         "fee": "1.3",
        #         "tradeType": "TRADE",
        #         "isTaker": True,
        #         "createdTime": 1701563440000
        #     }
        #
        marketId = self.safe_string_2(trade, 'm', 'market')
        market = self.safe_market(marketId, market)
        timestamp = self.safe_integer_2(trade, 'T', 'createdTime')
        priceString = self.safe_string_2(trade, 'p', 'price')
        amountString = self.safe_string_2(trade, 'q', 'qty')
        sideRaw = self.safe_string_2(trade, 'S', 'side')
        side = sideRaw.lower() if (sideRaw is not None) else None
        feeCost = self.safe_string(trade, 'fee')
        fee = None if (feeCost is None) else {
            'cost': feeCost,
            'currency': None if (market is None) else market['settle'],
        }
        isTaker = self.safe_bool(trade, 'isTaker')
        takerOrMaker = None
        if isTaker is not None:
            takerOrMaker = 'taker' if isTaker else 'maker'
        return self.safe_trade({
            'id': self.safe_string_2(trade, 'i', 'id'),
            'info': trade,
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
            'symbol': market['symbol'],
            'order': self.safe_string(trade, 'orderId'),
            'type': None,
            'side': side,
            'takerOrMaker': takerOrMaker,
            'price': priceString,
            'amount': amountString,
            'cost': self.safe_string(trade, 'value'),
            'fee': fee,
        }, market)

    async def fetch_ohlcv(self, symbol: str, timeframe: str = '1m', since: Int = None, limit: Int = None, params={}) -> List[list]:
        """
        fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market

        https://api.docs.extended.exchange/#get-candles-history

        :param str symbol: unified symbol of the market to fetch OHLCV data for
        :param str timeframe: the length of time each candle represents
        :param int [since]: timestamp in ms of the earliest candle to fetch
        :param int [limit]: the maximum amount of candles to fetch, default 100
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.candleType]: candle type: 'trades'(default), 'mark-prices', or 'index-prices'
        :param str [params.price]: *ignored if params.candleType is set* 'mark' or 'index' for mark price and index price candles
        :param int [params.until]: end timestamp in ms for the requested period
        :returns int[][]: A list of candles ordered, open, high, low, close, volume
        """
        await self.load_markets()
        market = self.market(symbol)
        price = self.safe_string(params, 'price')
        candleType = self.safe_string(params, 'candleType')
        if candleType is None:
            if price == 'mark':
                candleType = 'mark-prices'
            elif price == 'index':
                candleType = 'index-prices'
            else:
                candleType = 'trades'
        until = self.safe_integer(params, 'until')
        params = self.omit(params, ['candleType', 'price', 'until'])
        request = {
            'market': market['id'],
            'candleType': candleType,
            'interval': self.safe_string(self.timeframes, timeframe, timeframe),
            'limit': limit if (limit is not None) else 100,
        }
        if until is not None:
            request['endTime'] = until
        response = await self.v1PublicGetInfoCandlesMarketCandleType(self.extend(request, params))
        #
        #     {
        #       "status": "OK",
        #       "data": [
        #         {
        #           "o": "75657.5",
        #           "l": "75657.5",
        #           "h": "75657.5",
        #           "c": "75657.5",
        #           "v": "0",
        #           "T": 1777517880000
        #         }
        #       ]
        #     }
        #
        data = self.safe_list(response, 'data', [])
        return self.parse_ohlcvs(data, market, timeframe, since, limit)

    def parse_ohlcv(self, ohlcv, market: Market = None) -> list:
        #
        #     {
        #       "o": "75657.5",
        #       "l": "75657.5",
        #       "h": "75657.5",
        #       "c": "75657.5",
        #       "v": "0",
        #       "T": 1777517880000
        #     }
        #
        return [
            self.safe_integer(ohlcv, 'T'),
            self.safe_number(ohlcv, 'o'),
            self.safe_number(ohlcv, 'h'),
            self.safe_number(ohlcv, 'l'),
            self.safe_number(ohlcv, 'c'),
            self.safe_number(ohlcv, 'v'),
        ]

    async def fetch_funding_rate_history(self, symbol: Str = None, since: Int = None, limit: Int = None, params={}) -> List[FundingRateHistory]:
        """
        fetches historical funding rate prices

        https://api.docs.extended.exchange/#get-funding-rates-history

        :param str symbol: unified symbol of the market to fetch funding rate history for
        :param int [since]: timestamp in ms of the earliest funding rate to fetch
        :param int [limit]: the maximum amount of entries to fetch
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param int [params.until]: timestamp in ms of the latest funding rate to fetch
        :param int [params.endTime]: exchange-specific end timestamp in ms of the latest funding rate to fetch
        :param int [params.cursor]: offset of the result set
        :param boolean [params.paginate]: default False, when True will automatically paginate by calling self endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
        :returns dict[]: a list of `funding rate structures <https://docs.ccxt.com/?id=funding-rate-history-structure>`
        """
        if symbol is None:
            raise ArgumentsRequired(self.id + ' fetchFundingRateHistory() requires a symbol argument')
        await self.load_markets()
        paginate = False
        paginate, params = self.handle_option_and_params(params, 'fetchFundingRateHistory', 'paginate')
        if paginate:
            return await self.fetch_paginated_call_cursor('fetchFundingRateHistory', symbol, since, limit, params, 'cursor', 'cursor', None, 10000)
        market = self.market(symbol)
        symbol = market['symbol']
        if limit is None:
            limit = 100
        until = self.safe_integer(params, 'until', self.milliseconds())
        endTime = self.safe_integer(params, 'endTime', until)
        params = self.omit(params, ['endTime', 'until'])
        if since is None:
            since = endTime - (limit * 60 * 60 * 1000)
        request = {
            'market': market['id'],
            'startTime': since,
            'endTime': endTime,
            'limit': limit,
        }
        response = await self.v1PublicGetInfoMarketFunding(self.extend(request, params))
        #
        #     {
        #       "status": "OK",
        #       "data": [
        #         {
        #           "m": "BTC-USD",
        #           "f": "0.000008",
        #           "T": 1777507201028
        #         }
        #       ],
        #       "pagination": {
        #         "cursor": 1784963886257016832,
        #         "count": 1
        #       }
        #     }
        #
        data = self.safe_list(response, 'data', [])
        pagination = self.safe_dict(response, 'pagination', {})
        cursor = self.safe_string(pagination, 'cursor')
        result = []
        dataLength = len(data)
        for i in range(0, dataLength):
            entry = data[i]
            if (cursor is not None) and (i == dataLength - 1):
                entry = self.extend(entry, {'cursor': cursor})
            result.append(self.parse_funding_rate_history(entry, market))
        sorted = self.sort_by(result, 'timestamp')
        return self.filter_by_symbol_since_limit(sorted, symbol, since, limit)

    def parse_funding_rate_history(self, info, market: Market = None):
        #
        #     {
        #       "m": "BTC-USD",
        #       "f": "0.000008",
        #       "T": 1777507201028
        #     }
        #
        marketId = self.safe_string(info, 'm')
        market = self.safe_market(marketId, market)
        timestamp = self.safe_integer(info, 'T')
        return {
            'info': info,
            'symbol': market['symbol'],
            'fundingRate': self.safe_number(info, 'f'),
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
        }

    async def fetch_open_interest_history(self, symbol: str, timeframe: str = '1h', since: Int = None, limit: Int = None, params={}):
        """
        Retrieves the open interest history of a currency

        https://api.docs.extended.exchange/#get-open-interest-history

        :param str symbol: unified CCXT market symbol
        :param str timeframe: '1h' or '1d'
        :param int [since]: the time(ms) of the earliest record to retrieve unix timestamp
        :param int [limit]: the maximum amount of open interest structures to retrieve
        :param dict [params]: exchange specific parameters
        :param int [params.until]: timestamp in ms of the latest open interest record to fetch
        :returns dict[]: an array of `open interest structures <https://docs.ccxt.com/?id=open-interest-structure>`
        """
        await self.load_markets()
        market = self.market(symbol)
        interval = self.safe_string(self.timeframes, timeframe)
        if not self.in_array(interval, ['PT1H', 'P1D']):
            raise BadRequest(self.id + ' fetchOpenInterestHistory() supports 1h and 1d timeframes only')
        if limit is None:
            limit = 100
        until = self.safe_integer(params, 'until', self.milliseconds())
        endTime = self.safe_integer(params, 'endTime', until)
        params = self.omit(params, ['endTime', 'until'])
        if since is None:
            since = endTime - (limit * self.parse_timeframe(timeframe) * 1000)
        request = {
            'market': market['id'],
            'interval': interval,
            'startTime': since,
            'endTime': endTime,
            'limit': limit,
        }
        response = await self.v1PublicGetInfoMarketOpenInterests(self.extend(request, params))
        #
        #     {
        #       "status": "OK",
        #       "data": [
        #         {
        #           "i": "112620590.6060360000000000",
        #           "I": "1473.1408400000000000",
        #           "t": 1777420800000
        #         }
        #       ]
        #     }
        #
        data = self.safe_list(response, 'data', [])
        return self.parse_open_interests_history(data, market, since, limit)

    def parse_open_interest(self, interest, market: Market = None):
        #
        #     {
        #       "i": "112620590.6060360000000000",
        #       "I": "1473.1408400000000000",
        #       "t": 1777420800000
        #     }
        #
        timestamp = self.safe_integer(interest, 't')
        return self.safe_open_interest({
            'symbol': self.safe_string(market, 'symbol'),
            'openInterestAmount': self.safe_number(interest, 'I'),
            'openInterestValue': self.safe_number(interest, 'i'),
            'baseVolume': self.safe_number(interest, 'I'),
            'quoteVolume': self.safe_number(interest, 'i'),
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
            'info': interest,
        }, market)

