    async def fetch_ledger(self, code: Str = None, since: Int = None, limit: Int = None, params={}) -> List[LedgerEntry]:
        """
        fetch the history of changes, actions done by the user or operations that altered the balance of the user

        https://api.docs.extended.exchange/#get-deposits-withdrawals-transfers-history

        :param str [code]: unified currency code
        :param int [since]: timestamp in ms of the earliest ledger entry
        :param int [limit]: max number of ledger entries to return
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param boolean [params.paginate]: default False, when True will automatically paginate by calling self endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
        :returns dict[]: a list of `ledger structures <https://docs.ccxt.com/?id=ledger>`
        """
        await self.load_markets()
        paginate = False
        paginate, params = self.handle_option_and_params(params, 'fetchLedger', 'paginate')
        if paginate:
            return await self.fetch_paginated_call_cursor('fetchLedger', code, since, limit, params, 'cursor', 'cursor', None, 50)
        currency = None
        if code is not None:
            currency = self.currency(code)
        request = {}
        if limit is not None:
            request['limit'] = limit
        response = await self.v1PrivateGetUserAssetOperations(self.extend(request, params))
        data = self.safe_list(response, 'data', [])
        pagination = self.safe_dict(response, 'pagination', {})
        cursor = self.safe_string(pagination, 'cursor')
        result = []
        dataLength = len(data)
        for i in range(0, dataLength):
            entry = data[i]
            if (cursor is not None) and (i == dataLength - 1):
                entry = self.extend(entry, {'cursor': cursor})
            result.append(entry)
        return self.parse_ledger(result, currency, since, limit)

    def parse_ledger_entry(self, item: dict, currency: Currency = None) -> LedgerEntry:
        #
        #     {
        #         "id": "1951255127004282880",
        #         "type": "TRANSFER",
        #         "status": "COMPLETED",
        #         "amount": "-3.0000000000000000",
        #         "fee": "0",
        #         "asset": 1,
        #         "time": 1754050449502,
        #         "accountId": 100009,
        #         "counterpartyAccountId": 100023
        #     }
        #
        timestamp = self.safe_integer(item, 'time')
        assetId = self.safe_string(item, 'asset')
        code = self.get_extended_currency_code_by_id(assetId, currency)
        ledgerCurrency = self.safe_currency(code, currency)
        amountString = self.safe_string(item, 'amount')
        direction = None
        if amountString is not None:
            direction = 'out' if Precise.string_lt(amountString, '0') else 'in'
        fee = None
        feeCost = self.safe_string(item, 'fee')
        if feeCost is not None:
            fee = {
                'currency': code,
                'cost': self.parse_number(Precise.string_abs(feeCost)),
            }
        return self.safe_ledger_entry({
            'info': item,
            'id': self.safe_string(item, 'id'),
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
            'direction': direction,
            'account': self.safe_string(item, 'accountId'),
            'referenceId': self.safe_string(item, 'transactionHash'),
            'referenceAccount': self.safe_string(item, 'counterpartyAccountId'),
            'type': self.parse_transaction_type(self.safe_string(item, 'type')),
            'currency': code,
            'amount': None if (amountString is None) else self.parse_number(Precise.string_abs(amountString)),
            'before': None,
            'after': None,
            'status': self.parse_transaction_status(self.safe_string(item, 'status')),
            'fee': fee,
        }, ledgerCurrency)

