    async def withdraw(self, code: str, amount: float, address: str, tag: Str = None, params={}) -> Transaction:
        """
        make a Starknet withdrawal

        https://api.docs.extended.exchange/#withdrawals

        :param str code: unified currency code
        :param float amount: the amount to withdraw
        :param str address: the Starknet address to withdraw to
        :param str tag: unused
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.chainId]: only STRK is supported
        :param int [params.settlementExpiration]: settlement expiration timestamp in seconds, defaults to now + 14 days + 60 seconds
        :returns dict: a `transaction structure <https://docs.ccxt.com/?id=transaction-structure>`
        """
        self.check_required_credentials()
        await self.load_markets()
        currency = self.currency(code)
        chainId = self.safe_string_upper_2(params, 'chainId', 'network', 'STRK')
        if chainId != 'STRK':
            raise BadRequest(self.id + ' withdraw() only supports Starknet withdrawals with chainId STRK')
        if len(address) <= 42:
            raise BadRequest(self.id + ' withdraw() requires a Starknet address for STRK withdrawals, EVM withdrawals require the bridge quote flow')
        account = await self.fetch_extended_account()
        amountString = self.currency_to_precision(code, amount)
        accountId = self.safe_string(account, 'accountId')
        settlement = self.create_withdrawal_settlement_data(address, amountString, currency, account, params)
        request = {
            'accountId': accountId,
            'amount': amountString,
            'chainId': chainId,
            'asset': currency['id'],
            'settlement': settlement,
        }
        params = self.omit(params, ['chainId', 'network', 'settlementExpiration', 'nonce', 'recipient', 'positionId', 'l2Vault', 'collateralId', 'resolution'])
        response = await self.v1PrivatePostUserWithdrawal(self.extend(request, params))
        #
        #     {
        #         "status": "OK",
        #         "data": 1820796462590083072
        #     }
        #
        now = self.milliseconds()
        return {
            'info': response,
            'id': self.safe_string(response, 'data'),
            'txid': None,
            'timestamp': now,
            'datetime': self.iso8601(now),
            'address': address,
            'addressFrom': None,
            'addressTo': address,
            'tag': tag,
            'tagFrom': None,
            'tagTo': tag,
            'type': 'withdrawal',
            'amount': self.parse_number(amountString),
            'currency': currency['code'],
            'status': 'pending',
            'updated': now,
            'fee': None,
            'network': chainId,
            'comment': None,
            'internal': False,
        }

